sqlMap.insert:

INSERT INTO TBL_SCHEDULEATTACH(
	ATTACHID, 							SCHEDULEID,					FILENAME, 				FILEPATH, 				FILESIZE,			TENANT_ID
) VALUES (
	SEQ_TBL_SCHEDULEATTACH.NEXTVAL,		#v_SCHEDULEID#,				#v_FILENAME#,			#v_FILEPATH#,			#v_FILESIZE#,		#v_TENANTID#
)


INSERT INTO TBL_SCHEDULEREPETITION_DEL(
	REPETITIONID,								SCHEDULEID,				STARTDATE, 				ENDDATE,				TENANT_ID,				COMPANYID
) VALUES (
	SEQ_TBL_SCHEDULE_REPEDEL.NEXTVAL,			#v_SCHEDULEID#,			TO_DATE(#v_STARTDATE#,'yyyy-mm-dd hh24:mi'),			TO_DATE(#v_STARTDATE#,'yyyy-mm-dd hh24:mi'),			#v_TENANTID#,			#v_COMPANYID#
)


INSERT INTO TBL_SCHEDULEGROUPMEMBER(
	groupid, 		memberid, 		membername, 		membername2,    memberdeptid, 		status, 	responsedate,					tenant_id,		writepermission
) VALUES (
	#v_GROUPID#,	#v_MEMBERID#,	#v_MEMBERNAME#,		#v_MEMBERNAME2#,	#v_MEMBERDEPTID#,     0,			SYS_EXTRACT_UTC(SYSTIMESTAMP),	#v_TENANTID#,	#v_WRITEPERMISSION#
)


INSERT INTO TBL_SCHEDULEGROUP(
	groupid, 		groupname, 			creatorid, 		creatorname, 		creatorname2, 		description,		createdate,			tenant_id,		COMPANYID,		groupcolor
) VALUES (
	#v_GUID#,		#v_GROUPNAME#,		#v_USERID#,		#v_DISPLAYNAME#,	#v_DISPLAYNAME2#,	#v_DESCRIPTION#,	SYS_EXTRACT_UTC(SYSTIMESTAMP),	#v_TENANTID#,	#v_COMPANYID#,	#v_GROUPCOLOR#
)


INSERT INTO TBL_SCHEDULECONFIG(
	userid, 			defaultview, 			startday, 				starttime, 				endtime, 			autodelete,			tenant_id,      remindertime	, defaultviewcheck
) VALUES (
	#v_USERID#,			#v_DEFAULTVIEW#,		#v_STARTDAY#,			#v_STARTTIME#,			#v_ENDTIME#,		#v_AUTODELETE#,		#v_TENANTID#,   #v_REMINDERTIME# , #v_DEFAULTVIEWCHECKBOX#
)


INSERT INTO TBL_SECRETARY(
	USERID, 		USERNAME, 			USERNAME2, 			SECRETARYID, 		SECRETARYNAME, 			TENANT_ID,			COMPANYID			
) VALUES (
	#v_USERID#,		#v_DISPLAYNAME#,	#v_DISPLAYNAME2#,	#v_SECRETARYID#,	#v_SECRETARYNAME#,		#v_TENANTID#,		#v_COMPANYID#
)


INSERT INTO TBL_SCHEDULEGATHER (
	groupid, groupname, creatorid, creatorname, creatorname2, description, createdate, tenant_id, COMPANYID
) VALUES (
	#v_GUID#, #v_GROUPNAME#, #v_USERID#, #v_DISPLAYNAME#, #v_DISPLAYNAME2#,	#v_DESCRIPTION#, SYS_EXTRACT_UTC(SYSTIMESTAMP),	#v_TENANTID#, #v_COMPANYID#
)


INSERT INTO TBL_SCHEDULEGATHERMEMBER (
	groupid, memberid, membername, membername2, memberdeptid, tenant_id
) VALUES (
	#v_GROUPID#, #v_MEMBERID#, #v_MEMBERNAME#, #v_MEMBERNAME2#, #v_MEMBERDEPTID#, #v_TENANTID#
)
